const positions = $input.all();
const timestamp = new Date().toISOString();

let totalValue = 0;
const rows = [];

for (const item of positions) {
  const p = item.json;
  const size = Number(p.size || 0);
  const avgPrice = Number(p.avgPrice || p.price || 0);
  const currentPrice = Number(p.currentPrice || p.price || 0);
  const value = size * currentPrice;
  const cost = size * avgPrice;
  const pnl = value - cost;
  const pnlPct = cost > 0 ? ((pnl / cost) * 100).toFixed(2) : '0.00';

  totalValue += value;

  rows.push({
    timestamp,
    market: p.market || p.tokenId || 'Unknown',
    outcome: p.outcome || 'N/A',
    size,
    avgPrice: avgPrice.toFixed(4),
    currentPrice: currentPrice.toFixed(4),
    value: value.toFixed(2),
    pnl: pnl.toFixed(2),
    pnlPercent: pnlPct,
    totalPortfolioValue: totalValue.toFixed(2)
  });
}

if (rows.length === 0) {
  rows.push({
    timestamp,
    market: 'No positions',
    outcome: '',
    size: 0,
    avgPrice: '0',
    currentPrice: '0',
    value: '0',
    pnl: '0',
    pnlPercent: '0',
    totalPortfolioValue: '0'
  });
}

return rows.map(r => ({ json: r }));
